                    <span class="u-title"> {{ item.post_title }}</span>
                </div>
            </div>
            <div class="p-notice-pagination" v-if="pages > 1">
                <el-pagination
                    class="m-pagination"
                    layout="pager"
                    :current-page.sync="page"
                    :page-size="per"
                    :total="total"
                    :pager-count="5"
                    @current-change="changePage"
                    :hide-on-single-page="true"
                />
                <div class="m-jump">
                    <el-input
                        v-model="index"
                        type="number"
                        class="u-input"
                        size="mini"
                        @keyup.enter.native="toJump"
                    ></el-input>
                    <span class="u-jump" @click="toJump">跳转</span>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import { getPosts } from "@/service/cms";
import notice_types from "@/assets/data/notice_types.json";
import NoticeToolbar from "./NoticeToolbar.vue";
export default {
    name: "NoticeList",
    components: { NoticeToolbar },
    data: function () {
        return {
            loading: false, //加载状态

            list: [], //数据列表
            page: 1, //当前页数
            total: 1, //总条目数
            pages: 1, //总页数
            per: 10, //每页条目
            index: "", // 跳转页面

            search: "",
            client: this.$store.state.client, //版本选择
            isAdmin: false,
            notice_types,
            subtype: "",
        };
    },
    computed: {
        params: function () {
            let params = {
                per: this.per,
                page: ~~this.page || 1,
                sticky: 1,
                type: "notice",
            };
            let optionalParams = ["search", "client", "subtype"];
            optionalParams.forEach((item) => {
                if (this[item]) {
                    params[item] = this[item];
                }
            });
            return params;
        },
    },
    methods: {
        loadPosts: function () {
            this.loading = true;
            getPosts(this.params, this)
                .then((res) => {
                    this.list = res.data.data.list;
                    this.total = res.data.data.total;
                    this.pages = res.data.data.pages;
                })
                .finally(() => {
                    this.loading = false;
                });
        },
        // 去详情页
        toDetail(id) {
            this.$router.push({ name: "single", params: { id } });
            window.scrollTo(0, 0);
        },
        changePage(i) {
            this.page = ~~i;
        },
        // 跳转
        toJump() {
            if (this.index > this.pages) this.index = this.pages;
            if (this.index < 1) this.index = 1;
            this.changePage(this.index);
            this.index = "";
        },
        // 搜索
        update({ search, subtype }) {
            this.search = search;
            this.subtype = subtype;
        },
    },

    watch: {
        params: {
            deep: true,
            immediate: true,
            handler: function (val) {
                this.loadPosts();
            },
        },
    },
};
</script>
